import Foundation
import TunedVoiceKit

/// Errors surfaced by ``TextReplacer`` to guard against silent data loss.
enum TextReplacerError: Error, LocalizedError {
    /// The on-disk replacements file exists but cannot be decoded, so writing would clobber
    /// user data that may still be recoverable (e.g. via a Keychain KEK fix). The caller
    /// must either repair the file or surface the error to the user; it must NOT blindly
    /// retry the save.
    case refusingToClobberUnreadableFile

    var errorDescription: String? {
        switch self {
        case .refusingToClobberUnreadableFile:
            return "Refusing to overwrite replacements.json because the existing file exists but cannot be decoded. The on-disk file has been preserved to avoid data loss."
        }
    }
}

/// Applies user-defined text replacements to transcription output.
/// Replacements are stored in a JSON file at
/// `~/Library/Application Support/<Flavor>/Data/vocabulary/replacements.json`.
///
/// The pure matching logic lives in `TextReplacerEngine` (TunedVoiceKit).
/// This wrapper adds file I/O, bundled defaults, and logging.
struct TextReplacer: Sendable {
    struct Application: Codable, Sendable, Equatable {
        let from: String
        let to: String

        init(from: String, to: String) {
            self.from = from
            self.to = to
        }

        init(_ appliedReplacement: TextReplacerEngine.AppliedReplacement) {
            self.from = appliedReplacement.from
            self.to = appliedReplacement.to
