**Step 1 — New file: TranscriptHistoryService.swift.** Write a `@MainActor final class TranscriptHistoryService` that takes `AppModel` as its only constructor argument — NOT `AppEnvironment`. Because `AppModel` is annotated `@Observable` (AppModel.swift), Swift's observation runtime tracks reads of `appModel.snapshot` automatically. Use `withObservationTracking` to re-arm on each change:

```swift
@MainActor final class TranscriptHistoryService {
    private let appModel: AppModel
    private(set) var history: [DictationSnapshot] = []

    init(appModel: AppModel) {
        self.appModel = appModel
        observeSnapshots()
    }

    private func observeSnapshots() {
        withObservationTracking {
            _ = appModel.snapshot
        } onChange: { [weak self] in
            Task { @MainActor [weak self] in
                guard let self else { return }
                history.append(appModel.snapshot)
                observeSnapshots()
            }
        }
    }
}
