#### Services/Transcription/ReplacementsFileCoordinator.swift
```swift
import Foundation

/// Serializes all file I/O access to `replacements.json` via Swift actor isolation.
///
/// The underlying `TextReplacer.loadReplacementsFromDisk()` and `TextReplacer.saveToDisk(_:)`
/// remain synchronous static methods. This actor wraps them so that concurrent callers
/// (VocabularySettingsView, SettingsView) cannot race on
/// load-modify-save sequences. See issue #778.
actor ReplacementsFileCoordinator {
    static let shared = ReplacementsFileCoordinator()
    private init() {}

    func load() -> [TextReplacer.Replacement] {
        TextReplacer.loadReplacementsFromDisk()
    }

    func save(_ replacements: [TextReplacer.Replacement]) throws {
        try TextReplacer.saveToDisk(replacements)
    }

    /// Atomic load-modify-save: loads current replacements, applies a mutation,
    /// and saves the result. Returns the mutated array.
    @discardableResult
    func modify(
        _ mutation: @Sendable (inout [TextReplacer.Replacement]) throws -> Void
    ) throws -> [TextReplacer.Replacement] {
        var replacements = TextReplacer.loadReplacementsFromDisk()
        try mutation(&replacements)
        try TextReplacer.saveToDisk(replacements)
        return replacements
    }
}

