import Foundation

/// Runs resource-loading smoke tests to catch Bundle.module crashes.
/// Invoked via `--smoke-test` CLI argument before SwiftUI starts.
enum SmokeTestRunner {
    struct Results {
        var failures: [String] = []
        var allPassed: Bool { failures.isEmpty }
    }

    static func run() -> Results {
        var results = Results()

        // Test 1: SafeResourceBundle resolves
        let bundle = SafeResourceBundle.resolve()
        if bundle.bundlePath.isEmpty {
            results.failures.append("SafeResourceBundle resolved to empty path")
        }

        // Test 2: replacements.sample.json
        if SafeResourceBundle.url(forResource: "replacements.sample", withExtension: "json") == nil {
            results.failures.append("replacements.sample.json not found")
        }

        // Test 3: replacements.default.json
        if SafeResourceBundle.url(forResource: "replacements.default", withExtension: "json") == nil {
            results.failures.append("replacements.default.json not found")
        }

        // Test 4: THIRD_PARTY_LICENSES.txt
        if SafeResourceBundle.url(forResource: "THIRD_PARTY_LICENSES", withExtension: "txt") == nil {
            results.failures.append("THIRD_PARTY_LICENSES.txt not found")
        }

        // Test 5: TunedVoiceKit bundle
        let kitBundle = SafeResourceBundle.resolve(bundleName: "TunedVoiceKit_TunedVoiceKit.bundle")
        if kitBundle.bundlePath.isEmpty {
            results.failures.append("TunedVoiceKit bundle resolved to empty path")
        }

        return results
    }
}

